const c = $input.item.json.candidate;
const directionArrow = { up: '↑', down: '↓', neutral: '→' }[c.direction] || '→';
const scoreBar = '█'.repeat(Math.round(c.score)) + '░'.repeat(10 - Math.round(c.score));
const narrative = c.narrative ? `<br/><span style="color:#666;font-size:12px">${c.narrative}</span>` : '';

const row = `<tr>
  <td style="padding:8px 12px;font-weight:bold">${c.ticker}</td>
  <td style="padding:8px 12px;color:#4CAF50">${directionArrow} ${c.direction.toUpperCase()}</td>
  <td style="padding:8px 12px;font-family:monospace">${c.score.toFixed(1)}/10 ${scoreBar}</td>
  <td style="padding:8px 12px;color:#888">${c.severity.toUpperCase()}</td>
  <td style="padding:8px 12px">${c.signal_type}${narrative}</td>
</tr>`;

return [{ json: { row, ticker: c.ticker, score: c.score } }];
